namespace schema_create_view_sales_summary {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  double price;
  int stock;
};

struct Sale {
  sqlgen::PrimaryKey<int, sqlgen::auto_incr> sale_id;
  int product_id;
  int quantity;
  double amount;
};

struct SalesSummary {
  static constexpr bool is_view = true;
  std::string product_name;
  int total_quantity;
  double total_revenue;
};

/**
 * Function: Create a view SalesSummary that aggregates sales by product.
 * 
 * @return true if view creation succeeds, false otherwise
 */
bool create_view_sales_summary() {
  // Connect to SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = *conn_result;

  // Construct the SELECT query using sqlgen::select_from
  auto query = sqlgen::select_from<Sale>(
      sqlgen::sum(&Sale::quantity).as<"total_quantity">(),
      sqlgen::sum(&Sale::amount).as<"total_revenue">(),
      &Product::name.as<"product_name">()
  ) | sqlgen::inner_join<Product>(&Sale::product_id == &Product::product_id)
    | sqlgen::group_by(&Product::name);

  // Create the view using sqlgen::create_as
  auto create_view_cmd = sqlgen::create_as<SalesSummary>(query);

  // Execute the command on the SQLite connection
  return create_view_cmd(conn);
}

}  // namespace schema_create_view_sales_summary
```

