  // 1. Connect to the database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite").value();

  // 2. Drop existing tables if they exist
  (sqlgen::drop<Parent> | sqlgen::if_exists)(conn).value();
  (sqlgen::drop<Child> | sqlgen::if_exists)(conn).value();

